    42|function parseGithubRepoSlug(value: string): string {
    43|  const normalized = (value || '').trim();
    44|  if (!normalized) return '';
    45|  if (/^[^/\s]+\/[^/\s]+$/.test(normalized)) return normalized.replace(/\.git$/i, '');
    46|  const m = normalized.match(/github\.com[/:]([^/\s]+)\/([^/.\s]+)(?:\.git)?/i);
    47|  return m ? `${m[1]}/${m[2]}` : '';
    48|}
