    50|async function readEnvOrOwnerVar(envName: string): Promise<string> {
    51|  const direct = (process.env[envName] ?? '').trim();
    52|  if (direct) return direct;
    53|  try {
    54|    const v = await getIVXOwnerVariableRuntimeValue(envName as Parameters<typeof getIVXOwnerVariableRuntimeValue>[0]);
    55|    return (v ?? '').trim();
    56|  } catch {
    57|    return '';
    58|  }
    59|}
    60|
    61|async function readGithubCreds(): Promise<{ token: string; repoUrl: string; repoSlug: string; branch: string }> {
    62|  const token = await readEnvOrOwnerVar('GITHUB_TOKEN');
    63|  const repoUrl = (process.env.GITHUB_REPO_URL ?? '').trim()
    64|    || (process.env.GITHUB_REPO ?? '').trim()
    65|    || await readEnvOrOwnerVar('GITHUB_REPO_URL');
    66|  const branch = (process.env.GITHUB_BRANCH ?? '').trim() || 'main';
    67|  return { token, repoUrl, repoSlug: parseGithubRepoSlug(repoUrl), branch };
    68|}
