    70|async function githubApi(token: string, urlPath: string): Promise<{ ok: boolean; status: number; data: unknown }> {
    71|  try {
    72|    const r = await fetch(`https://api.github.com${urlPath}`, {
    73|      headers: {
    74|        Authorization: `Bearer ${token}`,
    75|        Accept: 'application/vnd.github+json',
    76|        'X-GitHub-Api-Version': '2022-11-28',
    77|      },
    78|    });
    79|    let data: unknown = null;
    80|    try { data = await r.json(); } catch { data = null; }
    81|    return { ok: r.ok, status: r.status, data };
    82|  } catch (err) {
    83|    return { ok: false, status: 0, data: { error: err instanceof Error ? err.message : 'network_error' } };
    84|  }
    85|}
    86|
    87|function refSha(res: { ok: boolean; data: unknown }): string | null {
    88|  if (!res.ok || !res.data || typeof res.data !== 'object') return null;
    89|  const obj = (res.data as { object?: { sha?: string } }).object;
    90|  return obj?.sha ?? null;
    91|}
