    93|function runSyncGithubScript(env: NodeJS.ProcessEnv, message: string, timeoutMs: number): Promise<{ exitCode: number; stdout: string; stderr: string; timedOut: boolean }> {
    94|  return new Promise((resolve) => {
    95|    const scriptPath = path.resolve(process.cwd(), 'expo/sync-github.mjs');
    96|    const args = [scriptPath, '--message', message];
    97|    const child = spawn(process.execPath, args, {
    98|      env,
    99|      cwd: path.resolve(process.cwd(), 'expo'),
   100|      stdio: ['ignore', 'pipe', 'pipe'],
   101|    });
   102|    let stdout = '';
   103|    let stderr = '';
   104|    let timedOut = false;
   105|    const timer = setTimeout(() => { timedOut = true; try { child.kill('SIGKILL'); } catch {} }, timeoutMs);
   106|    child.stdout.on('data', (chunk) => { stdout += String(chunk); if (stdout.length > 200_000) stdout = stdout.slice(-200_000); });
   107|    child.stderr.on('data', (chunk) => { stderr += String(chunk); if (stderr.length > 50_000) stderr = stderr.slice(-50_000); });
   108|    child.on('close', (code) => { clearTimeout(timer); resolve({ exitCode: code ?? -1, stdout, stderr, timedOut }); });
   109|    child.on('error', (err) => { clearTimeout(timer); resolve({ exitCode: -1, stdout, stderr: stderr + String(err?.message ?? err), timedOut }); });
   110|  });
   111|}
