   113|function redactSecretsFromString(input: string, secrets: string[]): string {
   114|  let out = input;
   115|  for (const s of secrets) {
   116|    if (s && s.length >= 6) out = out.split(s).join('***');
   117|  }
   118|  return out;
   119|}
