   123|type RenderTriggerResult = {
   124|  triggered: boolean;
   125|  deployId: string | null;
   126|  status: string | null;
   127|  autoDeployFallback: boolean;
   128|  apiError: string | null;
   129|};
   130|
   131|async function triggerRenderDeploy(apiKey: string, serviceId: string, commitSha: string | null): Promise<RenderTriggerResult> {
   132|  const headers = {
   133|    Authorization: `Bearer ${apiKey}`,
   134|    'Content-Type': 'application/json',
   135|    Accept: 'application/json',
   136|  };
   137|  const url = `${RENDER_API_BASE_URL}/services/${encodeURIComponent(serviceId)}/deploys`;
   138|  const post = async (body: Record<string, unknown>): Promise<{ ok: boolean; status: number; data: unknown }> => {
   139|    try {
   140|      const r = await fetch(url, { method: 'POST', headers, body: JSON.stringify(body) });
   141|      let data: unknown = null;
   142|      try { data = await r.json(); } catch { data = null; }
   143|      return { ok: r.ok, status: r.status, data };
   144|    } catch (err) {
   145|      return { ok: false, status: 0, data: { error: err instanceof Error ? err.message : 'network_error' } };
   146|    }
   147|  };
   148|
   149|  let response = await post(commitSha ? { commitId: commitSha } : {});
   150|  const commitNotYetIngested = (resp: { status: number; data: unknown }): boolean =>
   151|    resp.status === 404 && JSON.stringify(resp.data ?? '').toLowerCase().includes('does not have a commit');
   152|  for (let attempt = 0; attempt < 4 && commitNotYetIngested(response); attempt += 1) {
   153|    await sleep(2500);
   154|    response = await post(commitSha ? { commitId: commitSha } : {});
   155|  }
   156|  if (commitNotYetIngested(response)) {
   157|    response = await post({});
   158|  }
   159|
   160|  if (!response.ok) {
   161|    return {
   162|      triggered: false,
   163|      deployId: null,
   164|      status: 'auto_deploy_on_commit',
   165|      autoDeployFallback: true,
   166|      apiError: `Render deploy trigger failed: ${response.status} ${JSON.stringify(response.data ?? '').slice(0, 300)}`,
   167|    };
   168|  }
   169|  const data = (response.data && typeof response.data === 'object' ? response.data : {}) as Record<string, unknown>;
   170|  const deploy = (data.deploy && typeof data.deploy === 'object' ? data.deploy : {}) as Record<string, unknown>;
   171|  const deployId = (typeof data.id === 'string' && data.id) || (typeof deploy.id === 'string' && deploy.id) || null;
   172|  const status = (typeof data.status === 'string' && data.status) || (typeof deploy.status === 'string' && deploy.status) || 'accepted';
   173|  return { triggered: true, deployId, status, autoDeployFallback: false, apiError: null };
   174|}
