   176|type HealthProbe = { httpStatus: number; sha: string | null; matched: boolean };
   177|
   178|async function probeProductionHealth(baseUrl: string, expectedSha: string | null, attempts: number): Promise<HealthProbe> {
   179|  const url = `${baseUrl.replace(/\/+$/, '')}/health`;
   180|  let last: HealthProbe = { httpStatus: 0, sha: null, matched: false };
   181|  for (let i = 0; i < attempts; i += 1) {
   182|    try {
   183|      const r = await fetch(url, { headers: { Accept: 'application/json' } });
   184|      let data: unknown = null;
   185|      try { data = await r.json(); } catch { data = null; }
   186|      const sha = data && typeof data === 'object' && typeof (data as { commit?: string }).commit === 'string'
   187|        ? (data as { commit: string }).commit.trim()
   188|        : null;
   189|      const matched = Boolean(expectedSha && sha && sha !== 'unknown' && sha === expectedSha);
   190|      last = { httpStatus: r.status, sha: sha ?? null, matched };
   191|      if (matched) return last;
   192|    } catch {
   193|      last = { httpStatus: 0, sha: null, matched: false };
   194|    }
   195|    if (i < attempts - 1) await sleep(5000);
   196|  }
   197|  return last;
   198|}
