   200|/**
   201| * POST /api/ivx/admin/sync-rork-to-github
   202| *
   203| * Owner-only. Body: { message?: string; timeoutMs?: number; healthAttempts?: number }
   204| */
   205|export async function handleIVXAdminSyncRorkToGithubRequest(request: Request): Promise<Response> {
   206|  const startedAt = new Date().toISOString();
   207|  try {
   208|    await assertIVXOwnerOnly(request);
   209|    const body = readObjectInput(await request.json().catch(() => ({})));
   210|    const message = typeof body.message === 'string' && body.message.trim().length > 0
   211|      ? body.message.trim().slice(0, 500)
   212|      : `sync: owner-approved Rork→GitHub→Render delivery ${startedAt}`;
   213|    const timeoutMs = typeof body.timeoutMs === 'number' && Number.isFinite(body.timeoutMs)
   214|      ? Math.min(Math.max(body.timeoutMs, 30_000), 10 * 60_000)
   215|      : 5 * 60_000;
   216|    const healthAttempts = typeof body.healthAttempts === 'number' && Number.isFinite(body.healthAttempts)
   217|      ? Math.min(Math.max(Math.trunc(body.healthAttempts), 1), 60)
   218|      : 24;
   219|
   220|    const { token, repoUrl, repoSlug, branch } = await readGithubCreds();
   221|    const renderApiKey = await readEnvOrOwnerVar('RENDER_API_KEY');
   222|    const renderServiceId = await readEnvOrOwnerVar('RENDER_SERVICE_ID');
   223|    const productionBaseUrl = await readEnvOrOwnerVar('PRODUCTION_BASE_URL');
   224|
   225|    // Preflight: GitHub credentials are mandatory; without them nothing can ship.
   226|    if (!token || !repoSlug) {
   227|      const missing = [
   228|        ...(!token ? ['GITHUB_TOKEN'] : []),
   229|        ...(!repoSlug ? ['GITHUB_REPO_URL'] : []),
   230|      ];
   231|      return ownerOnlyJson({
   232|        marker: IVX_ADMIN_SYNC_MARKER,
   233|        SYNC_HTTP_STATUS: 0,
   234|        GITHUB_PUSHED: 'NO',
   235|        GITHUB_HEAD_SHA: null,
   236|        GITHUB_COMMIT_URL: null,
   237|        RENDER_DEPLOY_TRIGGERED: 'NO',
   238|        RENDER_DEPLOY_ID: null,
   239|        RENDER_STATUS: null,
   240|        HEALTH_HTTP_STATUS: 0,
   241|        PRODUCTION_HEALTH_SHA: null,
   242|        MATCH_GITHUB_TO_HEALTH: 'NO',
   243|        FINAL_STATUS: 'FAILED',
   244|        FAILED_AT: 'preflight_github_credentials',
   245|        RAW_ERROR: 'Backend runtime cannot read GitHub credentials from env or Owner Variables.',
   246|        MISSING_ENV: missing,
   247|        NEXT_OWNER_ACTION: 'Set GITHUB_TOKEN and GITHUB_REPO_URL on the backend (Render env) and retry.',
   248|      }, 503);
   249|    }
   250|
   251|    // 1. Snapshot HEAD before push (rollback reference).
   252|    const beforeRef = await githubApi(token, `/repos/${repoSlug}/git/ref/heads/${encodeURIComponent(branch)}`);
   253|    const previousCommit = refSha(beforeRef);
   254|
   255|    // 2. Run the existing sync script with credentials injected via env only.
   256|    const childEnv: NodeJS.ProcessEnv = {
   257|      ...process.env,
   258|      RORK_AUTO_SYNC_ENABLED: 'true',
   259|      GITHUB_TOKEN: token,
   260|      GITHUB_REPO_URL: repoUrl,
   261|      GITHUB_REPO: repoSlug,
   262|      GITHUB_BRANCH: branch,
   263|    };
   264|    const exec = await runSyncGithubScript(childEnv, message, timeoutMs);
   265|    const secrets = [token, renderApiKey].filter((s): s is string => Boolean(s) && s.length >= 6);
   266|    const stdoutTail = redactSecretsFromString(exec.stdout, secrets).split('\n').slice(-40).join('\n');
   267|    const stderrTail = redactSecretsFromString(exec.stderr, secrets).split('\n').slice(-40).join('\n');
   268|    const scriptOk = exec.exitCode === 0 && !exec.timedOut;
   269|    const syncHttpStatus = exec.timedOut ? 504 : scriptOk ? 200 : 500;
   270|
   271|    // 3. Re-read branch ref to confirm the pushed HEAD SHA.
   272|    const afterRef = await githubApi(token, `/repos/${repoSlug}/git/ref/heads/${encodeURIComponent(branch)}`);
   273|    const githubHeadSha = refSha(afterRef);
   274|    const advanced = Boolean(previousCommit && githubHeadSha && previousCommit !== githubHeadSha);
   275|    const noChanges = scriptOk && Boolean(githubHeadSha) && previousCommit === githubHeadSha;
   276|    const githubPushed = scriptOk && Boolean(githubHeadSha) && (advanced || noChanges);
   277|    const githubCommitUrl = githubHeadSha ? `https://github.com/${repoSlug}/commit/${githubHeadSha}` : null;
   278|
   279|    if (!githubPushed) {
   280|      return ownerOnlyJson({
   281|        marker: IVX_ADMIN_SYNC_MARKER,
   282|        SYNC_HTTP_STATUS: syncHttpStatus,
   283|        GITHUB_PUSHED: 'NO',
   284|        GITHUB_HEAD_SHA: githubHeadSha,
   285|        GITHUB_COMMIT_URL: githubCommitUrl,
   286|        RENDER_DEPLOY_TRIGGERED: 'NO',
   287|        RENDER_DEPLOY_ID: null,
   288|        RENDER_STATUS: null,
   289|        HEALTH_HTTP_STATUS: 0,
   290|        PRODUCTION_HEALTH_SHA: null,
   291|        MATCH_GITHUB_TO_HEALTH: 'NO',
   292|        FINAL_STATUS: 'FAILED',
   293|        FAILED_AT: exec.timedOut ? 'github_push_timeout' : 'github_push',
   294|        RAW_ERROR: (stderrTail || stdoutTail || 'sync-github.mjs did not advance the branch ref.').slice(0, 1200),
   295|        MISSING_ENV: [],
   296|        NEXT_OWNER_ACTION: 'Inspect the sync output below; verify GITHUB_TOKEN has push scope on the repo and the branch is not protected.',
   297|        previousCommit,
   298|        scriptExitCode: exec.exitCode,
   299|        scriptStdoutTail: stdoutTail,
   300|        scriptStderrTail: stderrTail,
   301|        timing: { startedAt, finishedAt: new Date().toISOString() },
   302|      }, 502);
   303|    }
   304|
   305|    // 4. Trigger Render deploy (best-effort; push-to-main auto-deploy is the fallback).
   306|    let render: RenderTriggerResult = { triggered: false, deployId: null, status: 'not_configured', autoDeployFallback: true, apiError: null };
   307|    const renderMissing: string[] = [];
   308|    if (renderApiKey && renderServiceId) {
   309|      render = await triggerRenderDeploy(renderApiKey, renderServiceId, githubHeadSha);
   310|    } else {
   311|      if (!renderApiKey) renderMissing.push('RENDER_API_KEY');
   312|      if (!renderServiceId) renderMissing.push('RENDER_SERVICE_ID');
   313|      render.apiError = `Render API not configured (${renderMissing.join(', ')}); relying on push-to-main auto-deploy.`;
   314|    }
   315|
   316|    // 5. Poll live /health and compare its commit SHA against GitHub HEAD.
   317|    let health: HealthProbe = { httpStatus: 0, sha: null, matched: false };
   318|    if (productionBaseUrl) {
   319|      health = await probeProductionHealth(productionBaseUrl, githubHeadSha, healthAttempts);
   320|    }
   321|
   322|    const matched = health.matched;
   323|    const finalStatus = matched
   324|      ? 'VERIFIED_LIVE_RORK_TO_GITHUB_TO_RENDER_COMPLETE'
   325|      : 'PARTIAL';
   326|
   327|    const payload: Record<string, unknown> = {
   328|      marker: IVX_ADMIN_SYNC_MARKER,
   329|      SYNC_HTTP_STATUS: syncHttpStatus,
   330|      GITHUB_PUSHED: 'YES',
   331|      GITHUB_HEAD_SHA: githubHeadSha,
   332|      GITHUB_COMMIT_URL: githubCommitUrl,
   333|      RENDER_DEPLOY_TRIGGERED: render.triggered ? 'YES' : (render.autoDeployFallback ? 'AUTO_DEPLOY_ON_COMMIT' : 'NO'),
   334|      RENDER_DEPLOY_ID: render.deployId,
   335|      RENDER_STATUS: render.status,
   336|      HEALTH_HTTP_STATUS: health.httpStatus,
   337|      PRODUCTION_HEALTH_SHA: health.sha,
   338|      MATCH_GITHUB_TO_HEALTH: matched ? 'YES' : 'NO',
   339|      FINAL_STATUS: finalStatus,
   340|      previousCommit,
   341|      changed: advanced,
   342|      timing: { startedAt, finishedAt: new Date().toISOString() },
   343|    };
   344|
   345|    if (!matched) {
   346|      payload.FAILED_AT = !productionBaseUrl
   347|        ? 'health_verification_no_base_url'
   348|        : health.httpStatus === 0
   349|          ? 'health_unreachable'
   350|          : 'health_sha_mismatch_or_pending';
   351|      payload.RAW_ERROR = !productionBaseUrl
   352|        ? 'PRODUCTION_BASE_URL is not readable by the backend runtime, so /health could not be verified.'
   353|        : health.httpStatus === 0
   354|          ? `Could not reach ${productionBaseUrl.replace(/\/+$/, '')}/health within ${healthAttempts} attempts.`
   355|          : `Live /health commit ${health.sha ?? 'unknown'} did not match GitHub HEAD ${githubHeadSha} (deploy may still be in progress).`;
   356|      payload.MISSING_ENV = [
   357|        ...(!productionBaseUrl ? ['PRODUCTION_BASE_URL'] : []),
   358|        ...renderMissing,
   359|      ];
   360|      payload.NEXT_OWNER_ACTION = !productionBaseUrl
   361|        ? 'Set PRODUCTION_BASE_URL on the backend, then re-call this endpoint to verify /health.'
   362|        : 'Wait for the Render deploy to finish, then re-call this endpoint; /health will report the new commit once live.';
   363|      if (render.apiError) payload.RENDER_API_NOTE = render.apiError;
   364|    }
   365|
   366|    return ownerOnlyJson(payload, matched ? 200 : 202);
   367|  } catch (error) {
   368|    return ownerOnlyJson({
   369|      marker: IVX_ADMIN_SYNC_MARKER,
   370|      SYNC_HTTP_STATUS: 0,
   371|      GITHUB_PUSHED: 'NO',
   372|      GITHUB_HEAD_SHA: null,
   373|      GITHUB_COMMIT_URL: null,
   374|      RENDER_DEPLOY_TRIGGERED: 'NO',
   375|      RENDER_DEPLOY_ID: null,
   376|      RENDER_STATUS: null,
   377|      HEALTH_HTTP_STATUS: 0,
   378|      PRODUCTION_HEALTH_SHA: null,
   379|      MATCH_GITHUB_TO_HEALTH: 'NO',
   380|      FINAL_STATUS: 'FAILED',
   381|      FAILED_AT: 'owner_auth_or_unexpected_error',
   382|      RAW_ERROR: error instanceof Error ? error.message.slice(0, 500) : 'admin_sync_failed',
   383|      MISSING_ENV: [],
   384|      NEXT_OWNER_ACTION: 'Call this endpoint with a valid owner session (Authorization: Bearer <IVX_OWNER_TOKEN>).',
   385|    }, 401);
   386|  }
   387|}

